const resp = $.steps.fetchData.response || {};
const data = resp.data || {};
const md = data.markdown || '';
const fieldMapping = $.input.fieldMapping || 'Use reasonable field names. Include all data columns found.';

const prompt = `You are a data preparation specialist. Extract and transform data from the following scraped content into a clean, structured format ready for Google Sheets.

SOURCE URL: ${$.input.dataUrl}

FIELD MAPPING INSTRUCTIONS: ${fieldMapping}

SCRAPED CONTENT:
${md.slice(0, 8000)}

INSTRUCTIONS:
- Identify all tabular or repeating data in the content
- Extract each record with consistent fields
- Clean and normalize values (trim whitespace, fix formatting)
- Apply field mapping/renaming as specified
- Add a timestamp field to each record
- Remove duplicate entries

Return ONLY valid JSON:
{
  "headers": ["col1", "col2"],
  "records": [
    { "col1": "value", "col2": "value" }
  ],
  "totalRecords": 0,
  "dataSource": "${$.input.dataUrl}",
  "transformations": ["<list of transforms applied>"]
}`;
return { prompt };

let raw = $.steps.aiAnalysis.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { headers: [], records: [], totalRecords: 0, dataSource: $.input.dataUrl, transformations: [] }; }

const ai = $.steps.parseAI.output;
const records = ai.records || [];
const date = new Date().toISOString().split('T')[0];
const timestamp = new Date().toISOString();

const sheetData = records.map((record, i) => {
  const row = { '#': i + 1 };
  Object.keys(record).forEach(key => {
    let val = record[key];
    if (val === null || val === undefined) val = '';
    val = String(val).trim();
    row[key] = val;
  });
  if (!row['Timestamp']) row['Timestamp'] = timestamp;
  return row;
});

return { sheetData, recordCount: records.length, date, transformations: ai.transformations || [] };
